inputs.requestsPostBodySchema:
{
  "type": "object",
  "properties": {
    "phone_number": {
      "type": "string",
      "description": "Número de teléfono del cliente (requerido)"
    },
    "customer_id": {
      "type": "string",
      "description": "ID del cliente (opcional si existe)"
    },
    "product_sku": {
      "type": "string",
      "description": "SKU del producto (ej: PIR-C7-2055516)"
    },
    "product_brand": {
      "type": "string",
      "description": "Marca del producto (ej: Pirelli)"
    },
    "product_model": {
      "type": "string",
      "description": "Modelo del producto (ej: Cinturato P7)"
    },
    "wheel_size": {
      "type": "string",
      "description": "Medida de la rueda (ej: 205/55 R16)"
    },
    "quantity": {
      "type": "integer",
      "description": "Cantidad de productos",
      "default": 1
    },
    "unit_price": {
      "type": "number",
      "description": "Precio unitario del producto"
    },
    "total_price": {
      "type": "number",
      "description": "Precio total (quantity * unit_price)"
    },
    "discount_percentage": {
      "type": "number",
      "description": "Porcentaje de descuento aplicado",
      "default": 0
    },
    "final_price": {
      "type": "number",
      "description": "Precio final después del descuento"
    },
    "payment_method": {
      "type": "string",
      "description": "Método de pago (cash, credit_card, debit_card, transfer, etc.)"
    },
    "delivery_method": {
      "type": "string",
      "description": "Método de entrega (pickup | delivery)"
    },
    "delivery_address": {
      "type": "string",
      "description": "Dirección de entrega (requerida si delivery_method es 'delivery')"
    },
    "sale_status": {
      "type": "string",
      "description": "Estado de la venta",
      "default": "pending"
    },
    "agent_notes": {
      "type": "string",
      "description": "Notas adicionales del agente sobre la venta"
    },
    "chatflowid": {
      "type": "string",
      "description": "ID del chatflow (para detección automática de producto si no se proporciona product_sku)"
    },
    "sessionId": {
      "type": "string",
      "description": "ID de la sesión (para detección automática de producto)"
    },
    "chatId": {
      "type": "string",
      "description": "ID del chat (para detección automática de producto)"
    }
  },
  "required": [
    "phone_number"
  ],
  "additionalProperties": false
}

